import{_ as a,o as e,c as n,ae as s}from"./chunks/framework.BdQd5MxT.js";const u=JSON.parse('{"title":"Anthropic: Harness Design for Long-Running Agents","description":"","frontmatter":{},"headers":[],"relativePath":"bestpractice/anthropic-harness-design.md","filePath":"bestpractice/anthropic-harness-design.md"}'),o={name:"bestpractice/anthropic-harness-design.md"};function r(i,t,l,d,p,h){return e(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="anthropic-harness-design-for-long-running-agents" tabindex="-1">Anthropic: Harness Design for Long-Running Agents <a class="header-anchor" href="#anthropic-harness-design-for-long-running-agents" aria-label="Permalink to &quot;Anthropic: Harness Design for Long-Running Agents&quot;">​</a></h1><blockquote><p>来源:</p><ul><li><a href="https://anthropic.com/engineering/effective-harnesses-for-long-running-agents" target="_blank" rel="noreferrer">Effective harnesses for long-running agents</a> (2025-11-26)</li><li><a href="https://anthropic.com/engineering/harness-design-long-running-apps" target="_blank" rel="noreferrer">Harness design for long-running application development</a> (2026-03-24) 分析: WLB</li></ul></blockquote><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>长运行 Agent 的核心问题是如何<strong>跨 context window 保持连贯性</strong> — Anthropic 用 Feature List + Context Reset + Generator-Evaluator 分离解决。</p><hr><h2 id="失败模式" tabindex="-1">失败模式 <a class="header-anchor" href="#失败模式" aria-label="Permalink to &quot;失败模式&quot;">​</a></h2><h3 id="_1-一次性冲刺" tabindex="-1">1. 一次性冲刺 <a class="header-anchor" href="#_1-一次性冲刺" aria-label="Permalink to &quot;1. 一次性冲刺&quot;">​</a></h3><p>Agent 试图在一个 session 里干完所有事 → context 耗尽 → 下个 session 从零开始。</p><h3 id="_2-过早宣布完成" tabindex="-1">2. 过早宣布完成 <a class="header-anchor" href="#_2-过早宣布完成" aria-label="Permalink to &quot;2. 过早宣布完成&quot;">​</a></h3><p>看到有进展就认为 job done → 后续 feature 被忽略。</p><h3 id="_3-context-anxiety" tabindex="-1">3. Context Anxiety <a class="header-anchor" href="#_3-context-anxiety" aria-label="Permalink to &quot;3. Context Anxiety&quot;">​</a></h3><p>Agent 快到 context limit 时开始&quot;收尾&quot; → 还没做完就草草结束。</p><h3 id="_4-自我评价过度自信" tabindex="-1">4. 自我评价过度自信 <a class="header-anchor" href="#_4-自我评价过度自信" aria-label="Permalink to &quot;4. 自我评价过度自信&quot;">​</a></h3><p>Agent 评价自己的作品 → 总是夸，即使质量很一般。</p><hr><h2 id="解法-1-双-agent-feature-list-2025-11" tabindex="-1">解法 1：双 Agent + Feature List (2025-11) <a class="header-anchor" href="#解法-1-双-agent-feature-list-2025-11" aria-label="Permalink to &quot;解法 1：双 Agent + Feature List (2025-11)&quot;">​</a></h2><h3 id="架构" tabindex="-1">架构 <a class="header-anchor" href="#架构" aria-label="Permalink to &quot;架构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Initializer Agent（首次运行）</span></span>
<span class="line"><span>├── 创建 feature list (JSON, 全部标记 failing)</span></span>
<span class="line"><span>├── 创建 claude-progress.txt (进度日志)</span></span>
<span class="line"><span>├── 创建 init.sh (启动/测试脚本)</span></span>
<span class="line"><span>└── 初始 git commit</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Coding Agent（每次后续运行）</span></span>
<span class="line"><span>├── pwd → 读 git log + progress → 选最高优先级 failing feature</span></span>
<span class="line"><span>├── 只做一个 feature (增量)</span></span>
<span class="line"><span>├── 端到端测试 (browser automation, 不是 curl)</span></span>
<span class="line"><span>├── git commit + 更新 progress</span></span>
<span class="line"><span>└── 清理状态后退出</span></span></code></pre></div><h3 id="关键设计" tabindex="-1">关键设计 <a class="header-anchor" href="#关键设计" aria-label="Permalink to &quot;关键设计&quot;">​</a></h3><p><strong>Feature List 用 JSON，不用 Markdown</strong></p><blockquote><p>&quot;The model is less likely to inappropriately change or overwrite JSON files compared to Markdown files.&quot;</p></blockquote><ul><li>每个 feature 有 <code>passes: true/false</code></li><li>强约束：&quot;不允许删除或编辑测试条目&quot;</li><li>Claude.ai clone 有 200+ 个 feature</li></ul><p><strong>增量工作</strong></p><ul><li>每次只做 <strong>一个</strong> feature</li><li>做完必须测试 + commit + 更新 progress</li></ul><p><strong>端到端测试</strong></p><ul><li>用 Puppeteer/Playwright 做 browser automation</li><li>不用 curl — &quot;Claude was able to identify and fix bugs that weren&#39;t obvious from the code alone&quot;</li><li>截图验证，不只是文本输出</li></ul><p><strong>Session 启动标准流程</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. pwd — 确认工作目录</span></span>
<span class="line"><span>2. 读 git log + progress.txt — 了解上下文</span></span>
<span class="line"><span>3. 读 feature list — 选下一个任务</span></span>
<span class="line"><span>4. 跑 init.sh — 确认环境正常</span></span></code></pre></div><hr><h2 id="解法-2-三-agent-context-reset-2026-03" tabindex="-1">解法 2：三 Agent + Context Reset (2026-03) <a class="header-anchor" href="#解法-2-三-agent-context-reset-2026-03" aria-label="Permalink to &quot;解法 2：三 Agent + Context Reset (2026-03)&quot;">​</a></h2><h3 id="架构-1" tabindex="-1">架构 <a class="header-anchor" href="#架构-1" aria-label="Permalink to &quot;架构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Planner → Generator → Evaluator</span></span>
<span class="line"><span>                ↑           │</span></span>
<span class="line"><span>                └───────────┘ (反馈循环 5-15 轮)</span></span></code></pre></div><h3 id="context-reset-vs-compaction" tabindex="-1">Context Reset vs Compaction <a class="header-anchor" href="#context-reset-vs-compaction" aria-label="Permalink to &quot;Context Reset vs Compaction&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>Compaction</th><th>Context Reset</th></tr></thead><tbody><tr><td>Agent</td><td>同一个 agent 继续</td><td>全新 agent</td></tr><tr><td>历史</td><td>压缩后的摘要</td><td>清零，靠 handoff artifact</td></tr><tr><td>Context Anxiety</td><td>仍在</td><td>消除</td></tr><tr><td>连续性</td><td>好</td><td>依赖 handoff 质量</td></tr><tr><td>推荐</td><td>简单任务</td><td>长任务（Claude Sonnet 4.5 强制需要）</td></tr></tbody></table><blockquote><p>&quot;Claude Sonnet 4.5 exhibited context anxiety strongly enough that compaction alone wasn&#39;t sufficient, so context resets became essential.&quot;</p></blockquote><h3 id="generator-evaluator-分离" tabindex="-1">Generator-Evaluator 分离 <a class="header-anchor" href="#generator-evaluator-分离" aria-label="Permalink to &quot;Generator-Evaluator 分离&quot;">​</a></h3><p><strong>为什么分离？</strong></p><ul><li>Agent 自评 → 过度自信地夸</li><li>分离后 → Evaluator 可调教为&quot;怀疑论者&quot;</li></ul><p><strong>Evaluator 校准：</strong></p><ul><li>用 few-shot examples + 详细评分标准</li><li>Evaluator 用 Playwright MCP 直接操作页面</li><li>导航 → 截图 → 仔细研究 → 评分 + 详细批评</li></ul><p><strong>评分维度（设计场景）：</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>权重</th><th>说明</th></tr></thead><tbody><tr><td>设计质量</td><td>高</td><td>整体一致性 vs 拼凑感</td></tr><tr><td>原创性</td><td>高</td><td>有意识的设计决策 vs AI 模板味</td></tr><tr><td>工艺</td><td>低</td><td>排版、间距、色彩（Claude 默认就做得不错）</td></tr><tr><td>功能性</td><td>低</td><td>用户能否不猜就完成任务</td></tr></tbody></table><p>前两项权重高，因为 Claude 在后两项上已经很强。</p><h3 id="generator-的战略决策" tabindex="-1">Generator 的战略决策 <a class="header-anchor" href="#generator-的战略决策" aria-label="Permalink to &quot;Generator 的战略决策&quot;">​</a></h3><ul><li>分数趋势好 → <strong>精炼</strong>当前方向</li><li>分数走不动 → <strong>彻底换</strong>审美方向</li></ul><hr><h2 id="对我们的借鉴" tabindex="-1">对我们的借鉴 <a class="header-anchor" href="#对我们的借鉴" aria-label="Permalink to &quot;对我们的借鉴&quot;">​</a></h2><h3 id="直接可用" tabindex="-1">直接可用 <a class="header-anchor" href="#直接可用" aria-label="Permalink to &quot;直接可用&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Anthropic 做法</th><th>我们怎么做</th></tr></thead><tbody><tr><td>Feature list (JSON, failing/passing)</td><td>长项目用 JSON 追踪任务状态</td></tr><tr><td>claude-progress.txt</td><td>每个长项目都有进度文件</td></tr><tr><td>Context Reset &gt; Compaction</td><td>长任务主动 reset，handoff artifact 传状态</td></tr><tr><td>端到端测试 &gt; curl</td><td>Agent 项目用 browser automation 验证</td></tr><tr><td>JSON &gt; Markdown（防止模型乱改）</td><td>结构化数据用 JSON</td></tr></tbody></table><h3 id="架构层面" tabindex="-1">架构层面 <a class="header-anchor" href="#架构层面" aria-label="Permalink to &quot;架构层面&quot;">​</a></h3><p><strong>WLB+GSD = 天然的 Generator-Evaluator 模式</strong></p><ul><li>GSD = Generator（执行/构建）</li><li>WLB = Evaluator（评估/决策）</li><li>这正是 Anthropic 验证过的有效架构！</li></ul><p><strong>可以加强的：</strong></p><ol><li><strong>给 WLB 标准化的评分维度</strong> — 像 Anthropic 的四维度一样</li><li><strong>反馈循环</strong> — GSD 做完 → WLB 评估 → GSD 改进（现在是手动的，可以更结构化）</li><li><strong>Feature List 机制</strong> — 长项目用 JSON 追踪，不用 markdown checklist</li><li><strong>Context Reset</strong> — MEMORY.md 太长时主动 reset，不靠 compaction</li></ol><h3 id="引用" tabindex="-1">引用 <a class="header-anchor" href="#引用" aria-label="Permalink to &quot;引用&quot;">​</a></h3><blockquote><p>&quot;Separating the agent doing the work from the agent judging it proves to be a strong lever.&quot;</p></blockquote><blockquote><p>&quot;Tuning a standalone evaluator to be skeptical turns out to be far more tractable than making a generator critical of its own work.&quot;</p></blockquote><blockquote><p>&quot;The key insight was finding a way for agents to quickly understand the state of work when starting with a fresh context window.&quot;</p></blockquote><hr><p><em>上一篇: <a href="/LIP/bestpractice/anthropic-context-engineering.html">Context Engineering ←</a></em></p>`,61)])])}const g=a(o,[["render",r]]);export{u as __pageData,g as default};
